package uk.ac.ed.ltg.jdm.textdata;import java.io.File;/** * This wrapper class represents an annotated file. It holds information about * the file, the annotator's unique identifier and the document identifier. *  * <p> * It also implements the interface Comparable so collections of instances of * this class are ordered according to the annotator's unique identifier. */public class AnnotatedFile implements Comparable {	/** The annotator. */	String annotator;	/** The doc id. */	String docId;	/** The file. */	File file;	/**	 * The Constructor.	 * 	 * @param f	 *            the f	 * @param annot	 *            the annot	 * @param id	 *            the id	 */	public AnnotatedFile(final File f, final String annot, final String id) {		this.file = f;		this.annotator = annot;		this.docId = id;	}	/**	 * Compare to.	 * 	 * @param o	 *            the o	 * 	 * @return the int	 */	public int compareTo(final Object o) {		if (o == null)			return 0;		final AnnotatedFile ao = (AnnotatedFile) o;		if (getAnnotator() == null && ao.getAnnotator() == null)			return 0;		if (getAnnotator() == null)			return -1;		else if (ao.getAnnotator() == null)			return 1;		return this.getAnnotator().compareTo(ao.getAnnotator());	}	/**	 * Equals.	 * 	 * @param o	 *            the o	 * 	 * @return true, if equals	 */	@Override	public boolean equals(final Object o) {		return this.compareTo(o) == 0;	}	/**	 * Gets the annotator.	 * 	 * @return the annotator	 */	public String getAnnotator() {		return this.annotator;	}	/**	 * Gets the doc id.	 * 	 * @return the doc id	 */	public String getDocId() {		return this.docId;	}	/**	 * Gets the file.	 * 	 * @return the file	 */	public File getFile() {		return this.file;	}}